import mongoose from 'mongoose';
import { StudentRepository } from '@/infrastructure/repositories/student.repository';
import { SettingsRepository } from '@/infrastructure/database/repositories/settings.repository';
import { PaymentRepository } from '@/infrastructure/repositories/payment.repository';
import { IStudent } from '@/domain/interfaces/student.interface';
import { COURSE_TYPES } from '@/domain/constants/course.constants';
import { STUDENT_STATUSES } from '@/domain/constants/student.constants';
import { ExcelHelper } from '@/infrastructure/utils/excel.helper';
import { Response } from 'express';
import { SystemLogModel } from '../../infrastructure/database/models/system_log.model';
import { StudentModel } from '../../infrastructure/database/models/student.model';
import { CourseStudentModel } from '../../infrastructure/database/models/course_student.model';
import { CourseModel } from '../../infrastructure/database/models/course.model';
import { LicenseCategoryModel } from '../../infrastructure/database/models/license_category.model';
import { CityModel } from '../../infrastructure/database/models/city.model';
import { NotificationModel } from '../../infrastructure/database/models/notification.model';
import { UserService } from './user.service';
import { NotifyService } from './notify.service';
import { StatusTransitionHelper } from './status-transition.helper';
import { PaginationOptions } from '@/domain/types/pagination.types';
import fs from 'fs';
import logger from '@/infrastructure/logging/logger';
import { AppError } from '@/domain/exceptions/app-error';
import { UserModel } from '../../infrastructure/database/models/user.model';
import { RoleModel, UserRoleName } from '../../infrastructure/database/models/role.model';
import { UserRoleModel } from '../../infrastructure/database/models/user_role.model';

export class StudentService {
  private studentRepository: StudentRepository;
  private paymentRepository: PaymentRepository;
  private userService: UserService;
  private excelHelper: ExcelHelper;
  private notifyService: NotifyService;
  private settingsRepository: SettingsRepository;

  constructor() {
    this.studentRepository = new StudentRepository();
    this.paymentRepository = new PaymentRepository();
    this.userService = new UserService();
    this.excelHelper = new ExcelHelper();
    this.notifyService = new NotifyService();
    this.settingsRepository = new SettingsRepository();
  }

  async getAllStudents(filters = {}, options: PaginationOptions = { page: 1, limit: 10 }, currentUser?: any) {
    return await this.studentRepository.findAll(filters, options, currentUser);
  }

  async getStudentById(id: string, currentUser?: any) {
    const student = await this.studentRepository.findById(id, currentUser);
    if (!student) {
      throw new AppError('Học viên không tồn tại hoặc bạn không có quyền truy cập', 404);
    }
    return student;
  }

  async updateStudent(id: string, data: any) {
    const student = await this.studentRepository.findById(id);
    if (!student) throw new AppError('Học viên không tồn tại', 404);

    // Business Logic Guard: Validate status transition if requested
    if (data.status) {
      StatusTransitionHelper.validate(student, data.status);
    }

    // 1. Update Core User Data
    const userId = (student.user_id as any)._id || student.user_id;
    const coreFields = [
      'name',
      'first_name',
      'last_name',
      'phone',
      'identity_number',
      'identity_card',
      'email',
      'existing_license_num',
      'existing_license_rank',
    ];
    if (Object.keys(data).some((k) => coreFields.includes(k))) {
      await this.userService.updateUserProfile(userId, data);
    }

    // 2. Map and Update Core Student Attributes (Demographics & Category)
    const demographicUpdate: any = {};
    if (data.city !== undefined) {
      demographicUpdate.region_id =
        data.city === ''
          ? null
          : mongoose.Types.ObjectId.isValid(data.city)
            ? new mongoose.Types.ObjectId(data.city)
            : data.city;
    }
    if (data.region_id !== undefined) {
      demographicUpdate.region_id =
        data.region_id === ''
          ? null
          : mongoose.Types.ObjectId.isValid(data.region_id)
            ? new mongoose.Types.ObjectId(data.region_id)
            : data.region_id;
    }

    // ENSURE: license_category_id is ALSO updated on the Student document, not just CourseStudent
    if (data.rank !== undefined && data.rank !== '') {
      demographicUpdate.license_category_id = await this._resolveLicenseCategoryId(data.rank);
    } else if (data.license_category_id !== undefined && data.license_category_id !== '') {
      demographicUpdate.license_category_id = await this._resolveLicenseCategoryId(data.license_category_id);
    }

    if (data.status !== undefined && data.status !== '') {
      let sanitizedStatus = data.status;
      if (sanitizedStatus === 'Đã xong KSK') sanitizedStatus = 'Đã KSK';
      demographicUpdate.status_detail = sanitizedStatus;
    }

    if (data.lead_manager !== undefined) {
      demographicUpdate.lead_manager = data.lead_manager === '' ? null : data.lead_manager;
    }

    if (Object.keys(demographicUpdate).length > 0) {
      await this.studentRepository.update(id, demographicUpdate);
    }

    // 3. Map Course details for latest CourseStudent Enrollment
    const courseUpdate = await this._mapCourseUpdateData(data);

    const needsEnrollmentUpdate =
      Object.keys(courseUpdate).length > 0 ||
      [
        'health_check_status',
        'health_check_date',
        'hospital_id',
        'health_check_note',
        'theory_completed',
        'sand_yard_completed',
        'simulation_completed',
        'dat_completed',
        'cabin_completed',
        'graduation_eligible',
      ].some((k) => data[k] !== undefined);

    if (needsEnrollmentUpdate) {
      const latestEnrollment = await CourseStudentModel.findOne({ student_id: id }).sort({ created_at: -1 });
      if (latestEnrollment) {
        this._mergeLatestEnrollmentFlags(courseUpdate, latestEnrollment, data);
        await CourseStudentModel.updateOne({ _id: latestEnrollment._id }, { $set: courseUpdate });
      } else {
        const fallbackCourseId =
          courseUpdate.course_id ||
          (student as any).course_id ||
          data.course_id ||
          data.course ||
          null;

        const fallbackLicenseCategoryId =
          courseUpdate.license_category_id ||
          (student as any).license_category_id ||
          null;

        if (fallbackCourseId) {
          const newEnrollment: any = {
            student_id: id,
            course_id: fallbackCourseId,
          };

          if (fallbackLicenseCategoryId) {
            newEnrollment.license_category_id = fallbackLicenseCategoryId;
          }

          this._mergeLatestEnrollmentFlags(newEnrollment, { health_check: {}, progress_flags: {} }, data);

          if (!newEnrollment.status_detail) {
            newEnrollment.status_detail = (student as any).status_detail || 'Chờ KSK';
          }

          if (courseUpdate.fee !== undefined) {
            newEnrollment.fee = courseUpdate.fee;
          }

          await CourseStudentModel.create(newEnrollment);
        } else {
          logger.warn('updateStudent: skipped enrollment-linked update because no enrollment/course could be resolved', {
            studentId: id,
            keys: Object.keys(data || {}),
          });
          throw new AppError(
            'Không thể cập nhật hồ sơ khám sức khỏe vì học viên chưa có khóa học/enrollment để lưu dữ liệu.',
            400,
          );
        }
      }
    }

    return await this.studentRepository.findById(id);
  }

  private async _mapCourseUpdateData(data: any): Promise<any> {
    const courseUpdate: any = {};
    if (data.status !== undefined) {
      // Sanitize old status labels coming from legacy clients or old constants
      let sanitizedStatus = data.status;
      if (sanitizedStatus === 'Đã xong KSK') sanitizedStatus = 'Đã KSK';
      courseUpdate.status_detail = sanitizedStatus;
    }
    if (data.course !== undefined && data.course !== '') {
      courseUpdate.course_id = data.course;
      // Fetch course fee to initialize tuition
      const course = await CourseModel.findById(data.course).select('course_fee').lean().exec();
      if (course) {
        courseUpdate.fee = (course as any).course_fee || 0;
      }
    }

    // Support both 'rank' string and 'license_category_id' ObjectId
    const rankValue = data.rank || data.license_category_id;
    if (rankValue !== undefined && rankValue !== '') {
      courseUpdate.license_category_id = await this._resolveLicenseCategoryId(rankValue);
    }
    return courseUpdate;
  }

  private async _resolveLicenseCategoryId(rank: string | null | undefined): Promise<any> {
    if (!rank) return null;
    // Already an ObjectId
    if (mongoose.Types.ObjectId.isValid(rank)) return rank;

    const normalized = rank.trim().toUpperCase();

    // 1. Exact match by code or name
    const exact = await LicenseCategoryModel.findOne({
      $or: [
        { code: { $regex: `^${normalized}$`, $options: 'i' } },
        { name: { $regex: `^${normalized}$`, $options: 'i' } },
        { name: { $regex: `^H\u1ea1ng ${normalized}$`, $options: 'i' } },
      ],
    }).exec();
    if (exact) return exact._id;

    // 2. Prefix fallback: 'B2' → tries 'B', 'A1' → tries 'A', etc.
    const prefix = normalized.replace(/\d+$/, '');
    if (prefix && prefix !== normalized) {
      const fallback = await LicenseCategoryModel.findOne({
        $or: [
          { code: { $regex: `^${prefix}$`, $options: 'i' } },
          { name: { $regex: `^${prefix}$`, $options: 'i' } },
          { name: { $regex: `^H\u1ea1ng ${prefix}$`, $options: 'i' } },
        ],
      }).exec();
      if (fallback) {
        logger.info('_resolveLicenseCategoryId: prefix fallback matched', { input: rank, matched: fallback.code });
        return fallback._id;
      }
    }

    logger.warn('_resolveLicenseCategoryId: no match found', { rank });
    return null;
  }

  private _mergeLatestEnrollmentFlags(courseUpdate: any, latestEnrollment: any, data: any) {
    const { health_check_status, health_check_date, hospital_id, health_check_note } = data;
    if ([health_check_status, health_check_date, hospital_id, health_check_note].some((v) => v !== undefined)) {
      const hc: any = latestEnrollment.health_check || {};

      let parsedDate = hc.date ?? null;
      if (health_check_date === '' || health_check_date === null) {
        parsedDate = null;
      } else if (health_check_date && health_check_date !== 'Invalid Date') {
        const d = new Date(health_check_date);
        if (!isNaN(d.getTime())) {
          parsedDate = d;
        }
      }

      courseUpdate.health_check = {
        status: health_check_status ?? hc.status ?? 'Chờ khám',
        date: parsedDate,
        hospital: hospital_id ?? hc.hospital ?? null,
        note: health_check_note ?? hc.note ?? null,
      };

      // --- DATA SYNCHRONIZATION: Health Check -> Dashboard Status ---
      // If health check status is updated to 'Đủ điều kiện', auto-set dashboard status to 'Đã KSK'
      // This ensures dashboard stats stay in sync with actual biological/medical progress.
      if (courseUpdate.health_check.status === 'Đủ điều kiện' && courseUpdate.status_detail !== 'Đã KSK') {
        courseUpdate.status_detail = 'Đã KSK';
      } else if (courseUpdate.health_check.status === 'Chờ khám' && latestEnrollment.status_detail === 'Đã KSK') {
        // If downgraded or reset, sync back to 'Chờ KSK'
        courseUpdate.status_detail = 'Chờ KSK';
      }
    }

    const {
      theory_completed,
      sand_yard_completed,
      simulation_completed,
      dat_completed,
      cabin_completed,
      graduation_eligible,
    } = data;
    if (
      [
        theory_completed,
        sand_yard_completed,
        simulation_completed,
        dat_completed,
        cabin_completed,
        graduation_eligible,
      ].some((v) => v !== undefined)
    ) {
      const pf: any = latestEnrollment.progress_flags || {};
      courseUpdate.progress_flags = {
        theory_completed: theory_completed ?? pf.theory_completed ?? false,
        sand_yard_completed: sand_yard_completed ?? pf.sand_yard_completed ?? false,
        simulation_completed: simulation_completed ?? pf.simulation_completed ?? false,
        dat_completed: dat_completed ?? pf.dat_completed ?? false,
        cabin_completed: cabin_completed ?? pf.cabin_completed ?? false,
        graduation_eligible: graduation_eligible ?? pf.graduation_eligible ?? false,
      };

      // --- DATA SYNCHRONIZATION: Exam Eligibility ---
      // If graduation_eligible is true, and status is still a training status, advance it to 'Đang thi'
      if (
        courseUpdate.progress_flags.graduation_eligible &&
        ['Đang học', 'Đang học LT', 'Đang học TH', 'Đã KSK', 'Nộp HS'].includes(latestEnrollment.status_detail)
      ) {
        courseUpdate.status_detail = 'Đang thi';
      }
    }
  }

  private async validateRequiredFields(data: any, userId: string) {
    const settings = await this.settingsRepository.findByUserId(userId);
    if (!settings || !settings.requiredFields || settings.requiredFields.length === 0) return;

    const MAPPING: Record<string, { field: string; label: string }> = {
      name: { field: 'name', label: 'Họ và tên' }, // Custom handling for name
      phone: { field: 'phone', label: 'Số điện thoại' },
      intro: { field: 'lead_manager', label: 'Người giới thiệu' },
      dob: { field: 'dob', label: 'Ngày sinh' },
      cccd: { field: 'identity_card', label: 'CCCD / CMND' },
      address: { field: 'address', label: 'Địa chỉ chi tiết' },
      rank: { field: 'license_category_id', label: 'Hạng bằng' },
      region: { field: 'region_id', label: 'Tỉnh / Thành phố' },
      course: { field: 'course_id', label: 'Khóa học' },
      regDate: { field: 'contract_date', label: 'Ngày đăng ký' },
    };

    for (const fieldId of settings.requiredFields) {
      const mapping = MAPPING[fieldId];
      if (!mapping) continue;

      if (fieldId === 'name') {
        if (!data.first_name || !data.last_name) {
          throw new AppError(`Trường [${mapping.label}] là bắt buộc`, 400);
        }
      } else {
        const value = data[mapping.field];
        if (value === undefined || value === null || value === '') {
          throw new AppError(`Trường [${mapping.label}] là bắt buộc`, 400);
        }
      }
    }
  }

  async createStudent(data: any, currentUser?: any) {
    const {
      phone,
      identity_card,
      user_id,
      region_id,
      course_id,
      fee,
      status_detail,
      license_category_id,
      amount,
      installment,
      lead_manager,
      student_code,
      teacher_id,
      contract_date,
      existing_license_num,
      existing_license_rank,
    } = data;

    // Dynamic settings validation
    if (currentUser?.id) {
      await this.validateRequiredFields(data, currentUser.id);
    }

    logger.info(`[StudentService.createStudent] Payload check:`, {
      teacher_id,
      phone,
      identity_card,
      existing_license_num,
      existing_license_rank
    });

    let targetUserId = user_id;

    // Sanitize status_detail
    let sanitizedStatus = status_detail || (course_id ? 'Đã vào khóa' : 'Chờ KSK');
    if (sanitizedStatus === 'Đã xong KSK') sanitizedStatus = 'Đã KSK';

    if (!targetUserId) {
      const existingUser = await this.userService.findExistingUser(phone, identity_card);
      if (existingUser) {
        // Check if this user already has a student record
        const existingStudent = await StudentModel.findOne({ user_id: existingUser._id, is_deleted: false }).exec();
        if (existingStudent) {
          throw new AppError('Học viên với số điện thoại hoặc CCCD này đã tồn tại.', 400);
        }

        // Update the existing user with any new license info provided
        if (existing_license_num || existing_license_rank) {
          await this.userService.updateUserProfile(existingUser._id.toString(), {
            existing_license_num,
            existing_license_rank
          });
        }

        targetUserId = existingUser._id;
      } else {
        const user = await this.userService.createStudentUser(data);
        targetUserId = user._id;
      }
    } else {
      // Check if this specific user_id is already a student
      const existingStudent = await StudentModel.findOne({ user_id: targetUserId, is_deleted: false }).exec();
      if (existingStudent) {
        throw new AppError('Người dùng này đã có hồ sơ học viên trên hệ thống.', 400);
      }
    }

    // Capture rank and status for the student profile (StudentInfos)
    const licenseCategoryId = await this._resolveLicenseCategoryId(license_category_id);

    let resolvedRegionId;
    if (region_id && typeof region_id === 'string' && !mongoose.Types.ObjectId.isValid(region_id)) {
      const city = await CityModel.findOne({ name: region_id }).select('_id').lean().exec();
      resolvedRegionId = city ? (city as any)._id : null;
    } else if (region_id && mongoose.Types.ObjectId.isValid(region_id)) {
      resolvedRegionId = new mongoose.Types.ObjectId(region_id);
    } else {
      resolvedRegionId = null;
    }

    const student = await this.studentRepository.create({
      user_id: targetUserId,
      region_id: resolvedRegionId as any,
      license_category_id: licenseCategoryId,
      status_detail: sanitizedStatus,
      lead_manager: lead_manager || null,
      student_code: student_code || null,
      teacher_id: teacher_id ? new mongoose.Types.ObjectId(teacher_id) : null,
    });

    if (course_id) {
      let actualFee = fee;
      if (!actualFee || actualFee === 0) {
        const course = await CourseModel.findById(course_id).select('course_fee').lean().exec();
        actualFee = (course as any)?.course_fee || 0;
      }

      const enrollment = await CourseStudentModel.create({
        student_id: student._id,
        course_id: course_id,
        teacher_id: teacher_id ? new mongoose.Types.ObjectId(teacher_id) : null,
        license_category_id: licenseCategoryId,
        fee: actualFee,
        status_detail: sanitizedStatus,
        contract_date: contract_date || null,
      });

      // Create initial payment if amount > 0
      if (amount && amount > 0) {
        // eslint-disable-next-line @typescript-eslint/no-require-imports
        const { PaymentModel } = require('@/infrastructure/database/models/payment.model');
        const receiptCode = await this.paymentRepository.getNextReceiptCode();

        await PaymentModel.create({
          course_student_id: enrollment._id,
          payment_date: new Date(),
          received_fee: amount,
          type: 'tuition_fee',
          stage_name: installment || 'Lần đóng 1',
          note: receiptCode,
          is_received: true,
        });
      }
    }

    // Return enriched data for immediate UI feedback
    return await this.getStudentById(student._id.toString());
  }

  async deleteStudent(id: string, currentUser?: any) {
    // 1. Verify existence and ownership
    await this.getStudentById(id, currentUser);

    // 2. Cascade delete any course enrollments mapped to this student
    await CourseStudentModel.deleteMany({ student_id: id });
    return await this.studentRepository.delete(id);
  }

  async bulkDeleteStudents(ids: string[], currentUser?: any) {
    if (!ids || ids.length === 0) {
      throw new Error('Danh sách ID không được để trống');
    }

    // 1. Verify existence and ownership for all
    // We could optimize this, but for safety we check all
    for (const id of ids) {
      await this.getStudentById(id, currentUser);
    }

    // 2. Cascade delete enrollments for all
    await CourseStudentModel.deleteMany({ student_id: { $in: ids } });

    // 3. Batch delete students
    return await this.studentRepository.deleteMany(ids);
  }

